+
+/// Create a basic context with minimal settings
+pub fn BasicContext() Context {
+    var ctx = Context{};
+    ctx.prec = 9;
+    ctx.rounding = .ROUND_HALF_UP;
+    ctx.setTrap(.DivisionByZero, true);
+    ctx.setTrap(.Overflow, true);
